from flask import Flask, request, redirect, session, url_for
from oauthlib.oauth2 import WebApplicationClient
import requests
import json
import os

app = Flask(__name__)
app.secret_key = os.urandom(24)

# Configuration
OPENID_PROVIDER = "https://<your-openid-provider>"
CLIENT_ID = "<client-id>"
CLIENT_SECRET = "<client-secret>"
REDIRECT_URI = "<redirect-uri>"

client = WebApplicationClient(CLIENT_ID)

@app.route("/")
def hello_world():
    return "Hello, World!"

@app.route("/login")
def login():
    authorization_endpoint = OPENID_PROVIDER + "/authorize"
    request_uri = client.prepare_request_uri(authorization_endpoint, redirect_uri=REDIRECT_URI)
    return redirect(request_uri)

@app.route("/callback")
def callback():
    code = request.args.get("code")
    token_endpoint = OPENID_PROVIDER + "/token"

    token_url, headers, body = client.prepare_token_request(
        token_endpoint,
        authorization_response=request.url,
        redirect_url=request.base_url,
        code=code
    )
    token_response = requests.post(
        token_url,
        headers=headers,
        data=body,
        auth=(CLIENT_ID, CLIENT_SECRET),
    )

    client.parse_request_body_response(json.dumps(token_response.json()))

    userinfo_endpoint = OPENID_PROVIDER + "/userinfo"
    uri, headers, body = client.add_token(userinfo_endpoint)
    userinfo_response = requests.get(uri, headers=headers, data=body)

    if userinfo_response.json()["email_verified"]:
        unique_id = userinfo_response.json()["sub"]
        users_email = userinfo_response.json()["email"]
        picture = userinfo_response.json()["picture"]
    else:
        return "User email not verified by Google.", 400

    session['id'] = unique_id
    session['email'] = users_email
    session['picture'] = picture

    return redirect(url_for(".hello_world"))

if __name__ == "__main__":
    app.run(ssl_context="adhoc")